
-- 100 Customers with realistic Indian names and Hyderabad addresses
-- First check if we already have enough customers
DO $$
DECLARE
  existing_count int;
BEGIN
  SELECT COUNT(*) INTO existing_count FROM customers;
  IF existing_count > 50 THEN
    RAISE NOTICE 'Already have % customers, skipping customer seed', existing_count;
    RETURN;
  END IF;

END;
$$;
